import { useState, useEffect } from 'react';
import { api, apiPost, apiPut } from '../utils/api';
import { tokens } from '../styles/tokens';

const colors = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, text: tokens.color.text, textSec: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple, cyan: tokens.color.cyan,
};
const mono = tokens.font.mono;
const body = tokens.font.sans;

const BOT_COLORS = ['#22d3ee', '#a78bfa', '#f59e0b', '#3fb950', '#f85149', '#58a6ff', '#bc8cff', '#d29922'];

/**
 * AddToBotModal — reusable modal for adding a strategy (or set of strategies) to a bot.
 *
 * Props:
 *   open       - boolean, whether modal is visible
 *   onClose    - () => void
 *   strategyKeys - string[] of strategy keys to add
 *   strategyLabel - string, display name for UI (e.g. "Breakout" or "3 strategies")
 *   onSuccess  - (botName) => void, called after successful assignment
 */
export default function AddToBotModal({ open, onClose, strategyKeys = [], strategyLabel = '', onSuccess }) {
  const [bots, setBots] = useState([]);
  const [loading, setLoading] = useState(true);
  const [step, setStep] = useState('select'); // 'select' | 'create'
  const [newBotName, setNewBotName] = useState('');
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(null);

  useEffect(() => {
    if (!open) return;
    setStep('select');
    setNewBotName('');
    setError(null);
    setSuccess(null);
    setSaving(false);
    setLoading(true);

    api('/bots')
      .then(data => {
        const list = data?.bots || [];
        setBots(list);
      })
      .catch(() => setBots([]))
      .finally(() => setLoading(false));
  }, [open]);

  if (!open) return null;

  const addToExistingBot = async (bot) => {
    setSaving(true);
    setError(null);
    try {
      const existing = Array.isArray(bot.strategies) ? bot.strategies : [];
      const merged = [...new Set([...existing, ...strategyKeys])];
      const res = await apiPut(`/bots/${bot.bot_name}`, { strategies: merged });
      if (!res || res.error) throw new Error(res?.error || 'Failed to update bot');
      setSuccess(`Added to ${bot.display_name || bot.bot_name}`);
      onSuccess?.(bot.bot_name);
      setTimeout(() => onClose(), 1200);
    } catch (e) {
      setError(e.message);
    }
    setSaving(false);
  };

  const createAndAdd = async () => {
    const name = newBotName.trim();
    if (!name) { setError('Bot name is required'); return; }
    setSaving(true);
    setError(null);
    try {
      const botKey = name.toLowerCase().replace(/[^a-z0-9]+/g, '_').replace(/^_|_$/g, '');
      const colorIdx = bots.length % BOT_COLORS.length;
      const res = await apiPost('/bots', {
        bot_name: botKey,
        display_name: name.toUpperCase(),
        venue: 'IBKR',
        color: BOT_COLORS[colorIdx],
        mode: 'PAPER',
        enabled: false,
        strategies: strategyKeys,
      });
      if (!res || res.error) throw new Error(res?.error || 'Failed to create bot');
      setSuccess(`Created ${name.toUpperCase()} with ${strategyKeys.length} ${strategyKeys.length === 1 ? 'strategy' : 'strategies'}`);
      onSuccess?.(botKey);
      setTimeout(() => onClose(), 1500);
    } catch (e) {
      setError(e.message);
    }
    setSaving(false);
  };

  return (
    <div
      onClick={onClose}
      style={{
        position: 'fixed', inset: 0, zIndex: 9999,
        background: 'rgba(0,0,0,0.65)', backdropFilter: 'blur(4px)',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        padding: 16, animation: 'fadeIn 0.15s ease',
      }}
    >
      <div
        onClick={e => e.stopPropagation()}
        style={{
          background: colors.surface, border: `1px solid ${colors.border}`,
          borderRadius: 14, width: '100%', maxWidth: 440,
          maxHeight: '80vh', display: 'flex', flexDirection: 'column',
          animation: 'slideUp 0.25s ease',
        }}
      >
        {/* Header */}
        <div style={{
          padding: '16px 20px', borderBottom: `1px solid ${colors.border}`,
          display: 'flex', justifyContent: 'space-between', alignItems: 'center',
        }}>
          <div>
            <div style={{ fontFamily: body, fontSize: 14, fontWeight: 700, color: colors.text }}>
              {step === 'create' ? 'Create New Bot' : 'Add to Bot'}
            </div>
            <div style={{ fontFamily: mono, fontSize: 11, color: colors.textSec, marginTop: 4 }}>
              {strategyLabel || `${strategyKeys.length} ${strategyKeys.length === 1 ? 'strategy' : 'strategies'}`}
            </div>
          </div>
          <button onClick={onClose} style={{
            background: 'none', border: 'none', color: colors.textSec,
            fontSize: 18, cursor: 'pointer', padding: '4px 8px', lineHeight: 1,
          }}>
            ×
          </button>
        </div>

        {/* Body */}
        <div style={{ flex: 1, overflow: 'auto', padding: '12px 20px 20px' }}>

          {/* Success / Error banners */}
          {success && (
            <div style={{
              background: 'rgba(63,185,80,0.12)', border: `1px solid ${colors.green}40`,
              borderRadius: 10, padding: '10px 14px', marginBottom: 12,
              fontFamily: mono, fontSize: 13, color: colors.green, fontWeight: 600,
            }}>
              {success}
            </div>
          )}
          {error && (
            <div style={{
              background: 'rgba(248,81,73,0.12)', border: `1px solid ${colors.red}40`,
              borderRadius: 10, padding: '10px 14px', marginBottom: 12,
              fontFamily: mono, fontSize: 13, color: colors.red,
            }}>
              {error}
            </div>
          )}

          {/* ── SELECT EXISTING BOT ── */}
          {step === 'select' && !success && (
            <>
              {loading ? (
                <div style={{ textAlign: 'center', padding: 32, color: colors.textSec, fontFamily: mono, fontSize: 13 }}>
                  Loading bots...
                </div>
              ) : (
                <>
                  {bots.length > 0 && (
                    <div style={{ marginBottom: 16 }}>
                      <div style={{ fontFamily: body, fontSize: 11, color: colors.textSec, textTransform: 'uppercase', letterSpacing: 0.5, marginBottom: 8 }}>
                        Existing Bots
                      </div>
                      <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                        {bots.map(bot => {
                          const hasStrategy = strategyKeys.every(k => (bot.strategies || []).includes(k));
                          return (
                            <button
                              key={bot.bot_name}
                              disabled={saving || hasStrategy}
                              onClick={() => addToExistingBot(bot)}
                              style={{
                                display: 'flex', alignItems: 'center', gap: 12,
                                padding: '10px 14px', borderRadius: 10,
                                border: `1px solid ${hasStrategy ? colors.border : colors.border}`,
                                background: hasStrategy ? `${colors.surface2}60` : colors.surface2,
                                cursor: hasStrategy ? 'default' : saving ? 'wait' : 'pointer',
                                opacity: hasStrategy ? 0.5 : 1,
                                transition: 'all 0.15s',
                                textAlign: 'left', width: '100%',
                              }}
                            >
                              {/* Bot color dot */}
                              <div style={{
                                width: 10, height: 10, borderRadius: '50%',
                                background: bot.color || colors.blue, flexShrink: 0,
                              }} />
                              <div style={{ flex: 1 }}>
                                <div style={{ fontFamily: mono, fontSize: 13, fontWeight: 700, color: colors.text }}>
                                  {bot.display_name || bot.bot_name?.toUpperCase()}
                                </div>
                                <div style={{ fontFamily: mono, fontSize: 10, color: colors.textSec }}>
                                  {bot.venue || 'IBKR'} · {bot.mode || 'DRY_RUN'} · {(bot.strategies || []).length} strategies
                                </div>
                              </div>
                              {hasStrategy ? (
                                <span style={{ fontFamily: mono, fontSize: 10, color: colors.green, fontWeight: 600 }}>
                                  ASSIGNED
                                </span>
                              ) : (
                                <span style={{ fontFamily: mono, fontSize: 11, color: colors.blue, fontWeight: 600 }}>
                                  + Add
                                </span>
                              )}
                            </button>
                          );
                        })}
                      </div>
                    </div>
                  )}

                  {/* Create New Bot button */}
                  <button
                    onClick={() => setStep('create')}
                    disabled={saving}
                    style={{
                      width: '100%', padding: '12px 16px', borderRadius: 10,
                      border: `1px dashed ${colors.blue}60`,
                      background: `${colors.blue}08`, cursor: 'pointer',
                      display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8,
                      fontFamily: mono, fontSize: 13, fontWeight: 600, color: colors.blue,
                      transition: 'all 0.15s',
                    }}
                  >
                    + Create New Bot
                  </button>
                </>
              )}
            </>
          )}

          {/* ── CREATE NEW BOT ── */}
          {step === 'create' && !success && (
            <>
              <button
                onClick={() => { setStep('select'); setError(null); }}
                style={{
                  background: 'none', border: 'none', cursor: 'pointer',
                  fontFamily: mono, fontSize: 11, color: colors.textSec, marginBottom: 12,
                  padding: 0, display: 'flex', alignItems: 'center', gap: 4,
                }}
              >
                ← Back to bot list
              </button>

              <div style={{ marginBottom: 16 }}>
                <label style={{ fontFamily: body, fontSize: 11, color: colors.textSec, textTransform: 'uppercase', letterSpacing: 0.5, display: 'block', marginBottom: 8 }}>
                  Bot Name
                </label>
                <input
                  type="text"
                  placeholder="e.g. Alpha Scalper"
                  value={newBotName}
                  onChange={e => setNewBotName(e.target.value)}
                  onKeyDown={e => e.key === 'Enter' && createAndAdd()}
                  autoFocus
                  style={{
                    width: '100%', padding: '10px 14px', borderRadius: 10,
                    border: `1px solid ${colors.border}`, background: colors.bg,
                    color: colors.text, fontFamily: mono, fontSize: 13,
                    outline: 'none', boxSizing: 'border-box',
                  }}
                />
                <div style={{ fontFamily: mono, fontSize: 10, color: colors.textSec, marginTop: 4 }}>
                  Bot starts in PAPER mode. Switch to LIVE from Bot Management.
                </div>
              </div>

              {/* Strategies being added */}
              <div style={{ marginBottom: 16 }}>
                <div style={{ fontFamily: body, fontSize: 11, color: colors.textSec, textTransform: 'uppercase', letterSpacing: 0.5, marginBottom: 8 }}>
                  Strategies
                </div>
                <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                  {strategyKeys.map(k => (
                    <span key={k} style={{
                      fontFamily: mono, fontSize: 10, fontWeight: 600,
                      padding: '3px 8px', borderRadius: 6,
                      background: 'rgba(167,139,250,0.12)', color: colors.purple,
                    }}>
                      {k.replace(/_/g, ' ')}
                    </span>
                  ))}
                </div>
              </div>

              <button
                onClick={createAndAdd}
                disabled={saving || !newBotName.trim()}
                style={{
                  width: '100%', padding: '11px 16px', borderRadius: 10,
                  border: 'none', fontFamily: mono, fontSize: 13, fontWeight: 700,
                  background: saving || !newBotName.trim() ? colors.surface2 : colors.green,
                  color: saving || !newBotName.trim() ? colors.textSec : tokens.color.bg,
                  cursor: saving || !newBotName.trim() ? 'not-allowed' : 'pointer',
                  transition: 'all 0.15s',
                }}
              >
                {saving ? 'Creating...' : 'Create Bot'}
              </button>
            </>
          )}
        </div>
      </div>

      <style>{`
        @keyframes fadeIn { from { opacity: 0 } to { opacity: 1 } }
        @keyframes slideUp { from { opacity: 0; transform: translateY(20px) } to { opacity: 1; transform: translateY(0) } }
      `}</style>
    </div>
  );
}
